SELECT "INEV" AS LineStatus, Item.[Trademark Code], Item.[Collection Code], Item.[Season Code], Item.[Line Code] AS LineCode, Item.[Product Family], Item.[Product Sex], Item.No_ AS Article, [Sales Line].[Constant Variable Code] AS Color, [Sales Line].[Promised Delivery Date] AS PromisedDeliveryDate, [Sales Line].[Requested Delivery Date] AS RequestedDeliveryDate, Date() AS DeliveryDate, "XXX" AS DeliveryNumber, "XXX" AS PostedNumber, [Sales Line].[Document No_] AS OrderNumber, [Sales Line].[Line No_] AS OrderLine, [Sales Header].[KIMO_FASHION SO No_], [Sales Line].Reference, [Sales Line].[Customer Order Ref_], [Sales Line].[assortment code] AS AssortmentCode, Val([outstanding quantity]) AS DeliveryQuantity, Val([outstanding quantity])*Val([no_ of pairs])/Val([quantity]) AS DeliveryPairs, Val([Sales Line.Line Amount])/Val([Sales Line.quantity])*Val([Sales Line.outstanding quantity]) AS DeliveryValue, [Sales Line].[Document Type], [Sales Line].[Delete Reason], Item.[Description 2], [Sales Line].[Sales_Purchase Status Code] AS CodStatusVendAcq, [Sales Line].[Sales_Purchase Status - Item] AS CodStatusVendAcqArticolo, Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status Date], Val([line discount _]) AS LineDiscount, Val([Sales Header.Invoice Discount Value]) AS InvoiceDiscount, IIf([Sales Header.Order Type]=1,"Riass.",IIf([Sales Header.order type]=2,"Pronto",IIf([Sales Header.order type]=3,"Stock",IIf([Sales Header.order type]=4,"Sost.",IIf([Sales Header.order type]=0,"Progr","?"))))) AS OrderType, Item.[advertising material]
FROM ([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_
WHERE (((Item.[Season Code])=[filtroStagione]) AND ((Val([outstanding quantity]))<>0) AND (([Sales Line].[Document Type])=1) AND (([Sales Line].[Delete Reason])="") AND (([Sales Line].type)=20));

